    """Adds a ``ctrans`` tag that conditionally renders a translation.

    ``{% ctrans condition [variables] [trimmed|notrimmed] %}...{% pluralize
    [variable] %}...{% fallback %}...{% endctrans %}``

    When ``condition`` evaluates truthy the translatable content is passed
    through ``gettext``/``ngettext`` exactly like the ``trans`` tag provided
    by :class:`InternationalizationExtension`. Otherwise the mandatory
    ``fallback`` block is rendered directly, with the same variable
    substitution rules, but without ever going through translation.
    """

    tags = {"ctrans"}

